var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"굉장하네요. 저 작은 무기에 침식체들이 맥도 못 추고 있어요.","JPN":"すごいですね。あの小さな武器に侵食体は為す術もないみたいです。","ENG":"Incredible. The C.O.s don’t stand a chance against that small weapon.","TWN":"好厲害，那個不起眼的小武器，竟然可以讓侵蝕體毫無招架之力。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"한나 씨, 뒤에!","JPN":"ハンナさん、後ろ！","ENG":"Miss Anderson, behind you!","TWN":"漢娜，小心後面！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"꺄앗!","JPN":"きゃあっ！","ENG":"Kyaah!","TWN":"哇啊！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"이걸로 급한 불은 껐군요. 괜찮으십니까?","JPN":"これで差し迫った問題は解決しましたね。お怪我はありませんか？","ENG":"I guess the most urgent problem's been dealt with. Are you okay?","TWN":"幸好這個來得及派上用場，你還好嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"하아, 감사합니다. 정신이 없어서 뒤에서 오는 줄도 몰랐어요.","JPN":"はあ、ありがとうございます。焦っていて後ろから来てるのも気づきませんでした。","ENG":"*Sigh* Thank you. I didn't even know one was coming from behind me.","TWN":"呼，謝謝你，我都沒注意到它們從後面撲上來。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"뭐죠? 지진인가?","JPN":"何でしょう？　地震かな？","ENG":"Huh? An earthquake?","TWN":"怎麼回事？是地震嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"침식체입니다! 거기서 피하세요!","JPN":"侵食体です！　避けてください！","ENG":"It's a C.O.! Get out of the way!","TWN":"是侵蝕體！快跑！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"꺄아아아! 뭐가 저렇게 커요? 이러다가 깔리겠어요!","JPN":"きゃあああ！　なんて大きさ！？　このままじゃ下敷きになっちゃいます！","ENG":"KYAAAH! Why's it so big?! We're gonna get crushed!!","TWN":"呃啊啊啊！怎麼塊頭這麼大？會被壓扁啦！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"큭……! 도망치긴 늦었나?","JPN":"くっ……！　もう逃げるには遅いか？","ENG":"Krrgh...! It's too late to run...!","TWN":"咳……！為時已晚嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"으으으……","JPN":"ううう……","ENG":"Err...","TWN":"呃呃呃……"},"stage":{"bg":"SKY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"어라? 살아 있네요?","JPN":"あれ？　生きてますね？","ENG":"Huh? We're alive?","TWN":"嗯？我還沒死？"},"stage":{"bg":"SKY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"그런데 저희 지금 뭘 타고 있는 거죠?","JPN":"ところで私たちが乗ってるこれって、何でしょう？","ENG":"But what's this thing we're riding on right now?","TWN":"不過我們現在在騎的是什麼？"},"stage":{"bg":"SKY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"이건…… 병기마?","JPN":"これは……兵器馬？","ENG":"Isn't this... an Armored Horse?","TWN":"這是…… 戰馬？"},"stage":{"bg":"SKY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"꺄아아! 큰 녀석이 계속 쫓아오고 있어요!","JPN":"きゃああ！　大きいやつがまだ追ってきてます！","ENG":"Kyaah! The giant C.O. is still chasing after us!","TWN":"呃啊啊！大塊頭一直追上來！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"허밋이 장교 분을 무사히 구출했습니다! 협곡 지대로 유인 중!","JPN":"ハーミットが将校を無事救出しました！　峡谷地帯へ誘導中！","ENG":"Hermit has safely rescued the officer! Currently luring the enemy into the valley!","TWN":"赫米特已經順利救出軍官！正將侵蝕體引至峽谷地帶！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"쐐기 대포의 준비 상황은 어떻지?","JPN":"くさび大砲の準備はどうだ？","ENG":"How are the preparations for the Ironshot Cannon going?","TWN":"楔子大砲準備得如何？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"설치를 마치고 발사각을 조정 중입니다.","JPN":"設置を終えて発射角度を調整しています。","ENG":"We've finished setting up, and are now in the process of adjusting the fire angle.","TWN":"設置完畢，正在調整發射角度。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"문제는 놈의 속도입니다. 보통 빠른 게 아니라 제대로 조준할 수가 없어요.","JPN":"問題はやつの速度です。速すぎてまともに照準が合わせられません。","ENG":"The problem is that monster's speed. It's too fast for us to get a good aim on it.","TWN":"問題那這傢伙的速度不是一般的快，很難瞄準。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"직접 겨냥할 필요 없다. 길목의 바위를 노려.","JPN":"直接狙う必要はない。道にある岩を狙え。","ENG":"There's no need to aim at it directly. Aim for the boulders in the canyon!","TWN":"不必瞄準，對準關口的岩石。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"으아아, 저 큰 녀석 아까보다 더 빨라진 거 아니에요? 이러다 곧 따라잡히겠어요!","JPN":"うああ、あの大きいやつ、さっきより速くなってません？　このままじゃ追いつかれちゃいます！","ENG":"Whooooa! It's getting faster! It's gaining on us!!","TWN":"呃啊啊，大塊頭是不是又更快啦？我們要被追上啦！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"아닙니다. 침식체가 빨라진 게 아니라 말이 느려지고 있는 거예요.","JPN":"いいえ。侵食体の速度が増しているのではなくて、馬が遅くなっているんです。","ENG":"No, the C.O. isn't getting faster, the horse it getting slower.","TWN":"不，不是侵蝕體變快，而是馬變慢。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"제가 무거워서 속도를 못 내는 건가요?! 역시 요즘 너무 먹어서 살찐 건가?!","JPN":"私が重くてスピード出ないんですか！？　やっぱり最近食べ過ぎて太っちゃったのかな！？","ENG":"Is it because I'm heavy?! D-did I gain weight from eating too much?!","TWN":"是因爲我太重所以跑不快嗎？！難道是因為我最近吃太多？！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"제가 아는 병기마의 성능은 탑승자의 체중 정도로 느려지지 않습니다.","JPN":"私の知る限り、兵器馬の性能は搭乗者の体重によって落ちたりはしません。","ENG":"As far as I know, Armored Horses don't get slower due to the weight of the rider.","TWN":"據我所知，戰馬的效能不會影因為騎乘者的體重而減速。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"이건… 의도적으로 속도를 늦추고 있는 것 같군요.","JPN":"これは……意図的に速度を落としてるようですね。","ENG":"It seems like... it's deliberately slowing down for some reason.","TWN":"似乎是…故意放慢速度的。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"한나 씨! 고삐를 잡으세요!","JPN":"ハンナさん！　手綱を掴んでください！","ENG":"Miss Anderson! Grab the reigns!","TWN":"漢娜！抓好繮繩！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"네? 네에!","JPN":"えっ？　はい！","ENG":"H-huh? Okay...!","TWN":"蛤？好！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_HORSE_RUNNING_01"},{"id":"L6_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"콜록, 콜록……!","JPN":"ゲホ、ゲホ……！","ENG":"*Cough!* *Cough!*","TWN":"咳咳，咳咳……！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"방금 어떻게 된 거예요? 갑자기 바위 기둥이 쓰러져서 침식체를 깔아뭉개 버렸어요!","JPN":"今の何が起こったんですか？　いきなり岩の柱が倒れて、侵食体を潰しちゃいましたよ！","ENG":"What just happened? The rock pillar just fell and crushed the C.O.!","TWN":"剛才是怎麼回事？岩柱突然就倒下來，將侵蝕體壓扁！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"혹시 노르드나빅의 전승 속에 나오는 요정 분들이 도와 주셨다거나?","JPN":"もしかしてノルドナビックの伝承の中に出てくる妖精さんが助けてくれたとか？","ENG":"Could it be that the fairies from Nordnavik's legends helped us?","TWN":"難道是諾爾德萊比傳說中的精靈現身幫忙嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"글쎄요. 요즘 같은 세상에 요정이 남아 있을지는 차치하고서라도…","JPN":"どうでしょう。今のような世界に妖精が残っているかどうかはともかく……","ENG":"I don't think so. Even if fairies still exist in this world...","TWN":"這個嘛，姑且不論現在的世界是否還存在著精靈…"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"저렇게 생겨 먹었을 것 같진 않군요.","JPN":"あんな姿をしてるとは思えませんね。","ENG":"They won't look like that.","TWN":"但精靈應該不是長那樣吧？"},"stage":{"bg":"SKY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"전원, 놈이 다시 움직이기 전에 마무리 짓는다!","JPN":"総員、やつがまた動く前に仕留める！","ENG":"All hands! We defeat the monster before it starts moving again!","TWN":"所有人聽著，在那傢伙再次起身前把它解決掉！"},"stage":{"bg":"SKY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"일제 사격!","JPN":"一斉射撃！","ENG":"Aim! FIRE!!","TWN":"全體射擊！"},"stage":{"bg":"SKY","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L24_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"감사합니다, 수비대 여러분. 덕분에 살았어요.","JPN":"ありがとうございます、守備隊のみなさん。おかげさまで命びろいしました。","ENG":"Thank you, Border Guards. I'm still alive thanks to all of you.","TWN":"謝謝護衛隊的大家，拜你們所賜我們才能得救。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"의무를 다했을 뿐입니다. 이걸로 저희에 대한 오해가 어느 정도 풀리면 좋겠군요.","JPN":"義務を果たしたまでです。これで我々への誤解がある程度解ければいいのですが。","ENG":"We were just doing our duty. I hope this will help resolve some of the misunderstandings you have about us.","TWN":"我們只是盡我們的責任而已，希望藉由這次的事能夠解開對我們的誤會。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"네, 물론이죠! 여러분은 저희에게 생명의 은인이세요!","JPN":"はい、もちろんです！　みなさんは私たちの命の恩人です！","ENG":"Oh, absolutely! You're our saviors!","TWN":"當然囉！你們都是我們的救命恩人！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"래시포드 장교님, 혹시 어디 다치신 곳은 없습니까?","JPN":"ラッシュフォード将校、お怪我はありませんか？","ENG":"Officer Rashford, are you hurt anywhere?","TWN":"雷斯福特軍官，你有沒有受傷？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그래. 신세를 졌다.","JPN":"大丈夫だ。世話になったな。","ENG":"No, and I owe you for that.","TWN":"是啊，幸虧有你們相救。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"우리가 침식체가 들끓는 곳에 제 발로 들어가길 기다렸다가, 보란 듯이 구해 줌으로써 뭘 얻으려고 한 건지는 모르겠지만.","JPN":"侵食体がうようよいる場所に足を踏み入れるのを待ってから、これ見よがしに助けることで何を得ようとしたのかはわからないがな。","ENG":"I'm not sure if you waited until we entered a C.O.-infested area before coming to the rescue to gain our trust, but...","TWN":"雖然我不清楚，你們等我們踏入滿是侵蝕體的地方後，再一副英雄之姿來救我們的目的是什麼？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"래, 래시포드 씨…….","JPN":"ら、ラッシュフォードさん……","ENG":"M-miss Rashford...","TWN":"雷…雷斯福特……"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"말해 봐라. 왜 외성 밖에 2종급의 대형 침식체가 있다는 걸 보고하지 않았지?","JPN":"言ってみろ。なぜ外郭の外に第2種レベルの大型侵食体がいるということを報告しなかった？","ENG":"Tell me. Why didn't you report that there were giant Category 2 C.O. out here?","TWN":"你說，爲什麼沒有事先報告，城外有2類大型侵蝕體？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"방금 전 해치운 대형 침식체는 저희에게도 생소한 부류였습니다.","JPN":"先ほど処理した大型の侵食体は、我々にとっても見慣れない部類でした。","ENG":"The giant C.O. we just defeated is an unfamiliar type to us as well.","TWN":"我們也是第一次遇到剛才那個大型侵蝕體，"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그리고 이 근방에 있었던 건, 직접 경호하면 장교님의 심기를 거스를 것 같아서였습니다.","JPN":"そしてこの辺りにいた理由は、直接警護することが将校のお気に障る可能性があると思ったからです。","ENG":"Also, the reason we were nearby was because I thought you'd be irritated if we accompanied you as your guards in front of you.","TWN":"而我們之所以會在這附近，是怕若直接隨行你會不高興。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"불쾌하셨다면 죄송합니다. 다른 의도는 없었습니다.","JPN":"不愉快にさせたのなら申し訳ありません。他意はありませんでした。","ENG":"I apologize if we offended you. We didn't have anything else in mind.","TWN":"若讓你感到不舒服，我很抱歉，但我沒有別的意思。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"흥, 잘도 그럴싸하게 포장하네.","JPN":"ふん、もっともらしいことを言う。","ENG":"Hmph. What a nice way to phrase it.","TWN":"哼，話說得這麼好聽。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"네 해명을 믿어 보겠다. 그래서, 답례로 뭘 원하지?","JPN":"釈明は信じよう。それで、何が欲しいんだ？","ENG":"I'll believe you. So, what do you want in return?","TWN":"我就姑且相信你，說吧，你想要什麼謝禮？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"특별히 없습니다만, 조사 중 안전을 위해 저희 부대를 동행시켜 주시면 기쁘겠습니다.","JPN":"特にはありませんが、調査中の安全のために我々部隊の同行を許可していただければ幸いです。","ENG":"Nothing in particular. However, I would appreciate it if you allowed my unit to accompany you during your investigation.","TWN":"只是一點小事而已，不過為確保你們調查時是安全的，請允許我們部隊一起陪同。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"많은 대원들이 이 나라의 국민으로서 열쇠를 찾는 데 일조하길 바라고 있으니까요.","JPN":"多くの隊員がこの国の国民として鍵を探すために力を貸したいと望んでいますから。","ENG":"As citizens of this country, we all want to help in finding the Key.","TWN":"因為大部分的隊員都希望，身為這個國家的國民，可能為尋找鑰匙貢獻己力。  "},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"좋다. 너희들의 실력은 내 눈으로 똑똑히 확인했으니까.","JPN":"いいだろう。貴様らの実力は自分の目でしっかり確認したからな。","ENG":"Very well. I've already seen what you're all capable of.","TWN":"好，我已經親眼確認過你們的實力，"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"하지만 오늘은 늦었으니 더 조사하긴 어렵겠어. 이만 외성으로 돌아가겠다.","JPN":"だが、今日は遅くなって、これ以上調査することは難しいだろう。この辺で外郭に戻る。","ENG":"However, it's getting late, so investigating any further today will be difficult. I'm going to head back to the outer castle.","TWN":"不過今天時間已晚，不方便調查，我決定要打道回城。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"래시포드 씨? 가, 같이 가요!","JPN":"ラッシュフォードさん？　ま、待ってください！","ENG":"Miss Rashford? W-wait for me!","TWN":"雷斯福特？等…等等我！"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"어려 보이는데 눈치가 빠르네.","JPN":"若く見えるのに勘がいいんだね。","ENG":"She looks young, but she catches on quickly.","TWN":"年紀輕輕卻很會察顏觀色呢。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"무슨 소리지?","JPN":"どういうことだ？","ENG":"What do you mean?","TWN":"什麼意思？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"당신도 선의만으로 저 고집불통을 돕자고 한 건 아니잖아?","JPN":"あなたも善意だけであの意地っ張りを助けようと言い出したわけじゃないんでしょ？","ENG":"You didn't want to help her out of sheer goodwill, did you?","TWN":"你會幫那個固執的軍官也不完全是出於善意吧？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"이 기회에 잘 보여서 함께 열쇠를 찾으려는 의도가 뻔히 보였다고.","JPN":"この機会にいい印象を与えて一緒に鍵を探そうとしてるのが見え見えだったよ。","ENG":"Your intention to find the Key together could be seen from a mile away.","TWN":"我知道你是想藉機討她開心，就可以一起去尋找鑰匙。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"……그렇게 노골적이었나?","JPN":"……そんなに露骨だったか？","ENG":"...Was it that obvious?","TWN":"……我的企圖有那麼明顯嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"저쪽은 그저 추측이었겠지만, 나는 당신 사정을 알고 있으니까.","JPN":"あちらは単なる推測だっただろうけど、私はあなたの事情を知ってるから。","ENG":"It could just be speculation on their part, but I'm well aware of your situation.","TWN":"對方可能不確定，但我知道你的心思。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그야 열쇠를 찾을 수 있는 단서가 눈앞에 나타났는데 두고만 보긴 힘들겠지.","JPN":"そりゃあ、鍵を探す手がかりが目の前に現れたんだし、ただ見ているだけというのは難しいでしょう。","ENG":"It's difficult to stay still when a clue to finding the Key appears right in front of your eyes.","TWN":"尋找鑰匙的線索就近在眼前，很難不心動吧？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"내키지 않는 일이라면 더 이상 부대를 끌어들이진 않겠어. 나 혼자서라도 돕지.","JPN":"気が進まないのなら、これ以上部隊を巻き込むことはしない。私一人ででも助けよう。","ENG":"If you wish, I won't involve the other troops anymore. I'll aid their investigation by myself.","TWN":"你不喜歡的話，我不會拖整個部隊下水，我一個人去就好。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"뭐래.","JPN":"何言ってるの。","ENG":"As if.","TWN":"你在說什麼？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"국경수비대가 재건단 일에 협조하지 않고 호위도 손 놓으면 뭘 하는데?","JPN":"国境守備隊が再建団の仕事に協力せず護衛もしないなら、いったい何をするっていうの？","ENG":"What are Border Guards supposed to do if we don't cooperate with the Alliance or provide escort?","TWN":"國境護衛隊不協助重建委員會，連隨行都不願意的話，那還能做什麼？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"저 장교가 마음에 안 들었던 것 아니었나?","JPN":"あの将校が気に入らないわけではなかったのか？","ENG":"I thought you didn't like her.","TWN":"你不是討厭那個軍官嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"재수없다고 생각한 건 부정하지 않을게. 이번 기회에 조금 정신 차리길 바랐던 것도.","JPN":"嫌なやつだと思ったのは否定しない。この機会に少しはまともになってくれることを期待したのも。","ENG":"I'm not going to pretend that I don't think she's a snob, or that I wanted her to know her place here.","TWN":"我承認她很討厭，也希望能夠藉此稍微振作起來。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"하지만 사라진 성유물을 되찾는 일은 당신만의 문제가 아냐. 우리 모두의 숙원이지.","JPN":"でも、消えた聖遺物を取り戻すことはあなただけの問題じゃない。みんなの宿願なんだから。","ENG":"But finding the lost Holy Relic isn't just your problem. It's something that we all want.","TWN":"但找回消失的聖遺物並不只是你一個人的問題，是我們所有人的心願。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"언젠가 낙원문이 다시 세워졌을 때, 거기에 걸맞은 열쇠가 필요할 테니까.","JPN":"いつかまた楽園の門が建てられた時、そこに合う鍵が必要になってくるから。","ENG":"Once Avalon's Gate is rebuilt, we'll need the Key back.","TWN":"因為當總有一天樂園門重建起來後，就會需要鑰匙。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…그래.","JPN":"……ああ。","ENG":"...You're right.","TWN":"…是的。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"나도 그러길 바라고 있어.","JPN":"私もそう願っている。","ENG":"I hope so too.","TWN":"我也希望如此。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};